class Job:
    def __init__(self, name, interval_minutes, func):
        self.name = name
        self.interval = interval_minutes
        self.func = func
        self.last_run = None    # Minutes since start when last run
        self.run_count = 0

    def is_due(self, current_time):
        """Return True if this job should run at current_time."""
        # TODO: Return True if last_run is None (never run)
        # or current_time - last_run >= interval
        pass

    def run(self, current_time):
        """Execute the job and update tracking."""
        self.func()
        self.last_run = current_time
        self.run_count += 1

class Scheduler:
    def __init__(self):
        self.jobs = []

    def every(self, interval_minutes, name=None):
        """Register a job to run every interval_minutes minutes."""
        def decorator(func):
            job_name = name or func.__name__
            self.jobs.append(Job(job_name, interval_minutes, func))
            return func
        return decorator

    def tick(self, current_time):
        """Advance time and run all due jobs."""
        for job in self.jobs:
            if job.is_due(current_time):
                job.run(current_time)

scheduler = Scheduler()
log = []  # Track what ran when

@scheduler.every(5, name="heartbeat")
def heartbeat():
    log.append("heartbeat")

@scheduler.every(15, name="report")
def daily_report():
    log.append("report")

@scheduler.every(30, name="cleanup")
def cleanup():
    log.append("cleanup")

# Simulate 35 minutes of ticks (every 5 min)
for t in range(0, 36, 5):
    scheduler.tick(t)

# Print what ran
print("Jobs run:")
for job in scheduler.jobs:
    print(f"  {job.name}: {job.run_count} times")

print(f"\nLog ({len(log)} entries):")
for entry in log:
    print(f"  {entry}")

